function WorkoutLogger() {
  const [exercises, setExercises] = React.useState([
    { name: 'Bench Press', sets: [{ reps: 10, weight: 135 }] }
  ]);
  const [newName, setNewName] = React.useState('');
  const addExercise = () => {
    if (!newName.trim()) return;
    setExercises([...exercises, { name: newName.trim(), sets: [{ reps: 0, weight: 0 }] }]);
    setNewName('');
  };
  const addSet = (ei) => {
    const next = exercises.map((ex, i) => i === ei ? { ...ex, sets: [...ex.sets, { reps: 0, weight: 0 }] } : ex);
    setExercises(next);
  };
  const updateSet = (ei, si, field, value) => {
    const next = exercises.map((ex, i) => i === ei ? { ...ex, sets: ex.sets.map((s, j) => j === si ? { ...s, [field]: Number(value) } : s) } : ex);
    setExercises(next);
  };
  const removeSet = (ei, si) => {
    const next = exercises.map((ex, i) => i === ei ? { ...ex, sets: ex.sets.filter((_, j) => j !== si) } : ex);
    setExercises(next);
  };
  const removeExercise = (ei) => {
    setExercises(exercises.filter((_, i) => i !== ei));
  };
  return (
    <div style={{ fontFamily: 'system-ui, sans-serif', padding: 16, background: '#fff', borderRadius: 12, height: '100%', boxSizing: 'border-box', display: 'flex', flexDirection: 'column' }}>
      <h3 style={{ margin: '0 0 12px 0', fontSize: 16, color: '#222' }}>Workout Log</h3>
      <div style={{ display: 'flex', gap: 8, marginBottom: 12 }}>
        <input value={newName} onChange={(e) => setNewName(e.target.value)} placeholder="Exercise name..." style={{ flex: 1, padding: '6px 10px', borderRadius: 8, border: '1px solid #ddd', fontFamily: 'inherit' }} />
        <button onClick={addExercise} style={{ padding: '6px 12px', borderRadius: 8, border: 'none', background: '#4f46e5', color: '#fff', cursor: 'pointer', fontFamily: 'inherit' }}>Add</button>
      </div>
      <div style={{ overflow: 'auto', flex: 1 }}>
        {exercises.map((ex, ei) => (
          <div key={ei} style={{ border: '1px solid #eee', borderRadius: 10, padding: 10, marginBottom: 10 }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 8 }}>
              <span style={{ fontWeight: 600, fontSize: 14, color: '#333' }}>{ex.name}</span>
              <button onClick={() => removeExercise(ei)} style={{ background: 'none', border: 'none', color: '#ef4444', cursor: 'pointer', fontSize: 16 }}>×</button>
            </div>
            <div style={{ display: 'grid', gridTemplateColumns: '30px 1fr 1fr 28px', gap: 6, alignItems: 'center', fontSize: 11, color: '#999', marginBottom: 4 }}>
              <span>#</span><span>Reps</span><span>Weight (lbs)</span><span></span>
            </div>
            {ex.sets.map((s, si) => (
              <div key={si} style={{ display: 'grid', gridTemplateColumns: '30px 1fr 1fr 28px', gap: 6, alignItems: 'center', marginBottom: 4 }}>
                <span style={{ fontSize: 12, color: '#666' }}>{si + 1}</span>
                <input type="number" value={s.reps} onChange={(e) => updateSet(ei, si, 'reps', e.target.value)} style={{ padding: '4px 8px', borderRadius: 6, border: '1px solid #ddd', fontFamily: 'inherit', fontSize: 13 }} />
                <input type="number" value={s.weight} onChange={(e) => updateSet(ei, si, 'weight', e.target.value)} style={{ padding: '4px 8px', borderRadius: 6, border: '1px solid #ddd', fontFamily: 'inherit', fontSize: 13 }} />
                <button onClick={() => removeSet(ei, si)} style={{ background: 'none', border: 'none', color: '#ef4444', cursor: 'pointer', fontSize: 14 }}>×</button>
              </div>
            ))}
            <button onClick={() => addSet(ei)} style={{ marginTop: 4, padding: '4px 10px', borderRadius: 6, border: '1px solid #ddd', background: '#fff', cursor: 'pointer', fontSize: 12, color: '#4f46e5', fontFamily: 'inherit' }}>+ Add Set</button>
          </div>
        ))}
      </div>
    </div>
  );
}
render(<WorkoutLogger/>);
